-- Bollenveld feiten: update full_description op basis van adres-slug
UPDATE locations SET full_description = 'De 1e Loosterweg in Hillegom biedt open zichtlijnen over de bollenakkers, die in het bloeiseizoen veranderen in kleurige tapijten van tulpen en hyacinten. Het weids polderlandschap achter deze weg is typerend voor Noord-Hillegom. — Hillegom / noord-bollengebied' WHERE slug = '1e-loosterweg-1';
UPDATE locations SET full_description = 'Ook in Hillegom draagt het netwerk van Loosterwegen bij aan de logistieke toegankelijkheid van de bollenpercelen. De 1e Loosterweg in dit deel van de Bollenstreek doorsnijdt actief bollenland. — Hillegom / Loosterweg-netwerk' WHERE slug = '1e-loosterweg-2';
UPDATE locations SET full_description = 'Rondom de 2e Doodweg in het noorden van Hillegom liggen bollenpercelen op goed doorlatende zandgrond. Dit type grond is essentieel voor bollenteelt, omdat bollen niet in stilstaand water mogen staan. — Hillegom / perifeer bollengebied' WHERE slug = '2e-doodweg-1';
UPDATE locations SET full_description = 'De naam ''Doodweg'' verwijst naar een historische weg die doodliep op een waterkant of perceelgrens. Dit soort wegen zijn kenmerkend voor de fijnmazige ontsluiting van het Hollandse bollengebied en bestaan al eeuwen. — Hillegom / perifeer bollengebied' WHERE slug = '2e-doodweg-2';
UPDATE locations SET full_description = 'Het noordelijke deel van de 3e Loosterweg grenst aan het open poldergebied richting Lisse-Noord, met uitgestrekte bollenvelden en een wijd uitzicht. Het vlakke karakter van dit landschap is kenmerkend voor de teeltgebieden op de geestrug. — Lisse / noordelijk bollengebied' WHERE slug = '3e-loosterweg-1';
UPDATE locations SET full_description = 'Wandelaars en fietsers die de 3e Loosterweg bewandelen, komen in het voorjaar oog in oog te staan met rijen bloeiende tulpen en hyacinten. Dit rustige lint is een alternatief voor de drukkere Heereweg, maar biedt hetzelfde kleurspektakel. — Lisse / Loosterweg-netwerk' WHERE slug = '3e-loosterweg-2';
UPDATE locations SET full_description = 'De 3e Loosterweg maakt deel uit van het uitgebreide Loosterweg-netwerk in Lisse, een systeem van parallelle bollenakkerlinten dat de productiviteit van de regio illustreert. Op deze percelen worden tulpen en andere bolgewassen op grote schaal geteeld. — Lisse / Loosterweg-netwerk' WHERE slug = '3e-loosterweg-3';
UPDATE locations SET full_description = 'De Achterweg in de duinenzone van Noordwijk loopt langs de binnenduinrand, waar bollenakkers afwisselen met duingebied. Dit westelijke deel van de Bollenstreek heeft een ruiger, wilder karakter dan de open polders verder oost. — Noordwijk / binnenduinrand' WHERE slug = 'achterweg-1';
UPDATE locations SET full_description = 'Het begin van de Achterweg Zuid sluit aan op het bredere wegennetwerk van de Bollenstreek. Dit type ontsluitingswegen zijn cruciaal voor de afvoer van geoogste bloembollen naar sorteer- en droogschuren. — Lisse / bollengebied' WHERE slug = 'achterweg-zuid-1';
UPDATE locations SET full_description = 'De naam ''Achterweg'' duidt op een secundaire weg die achter de bebouwing of de hoofdroute lag. Dit soort achterliggende linten zijn essentieel in de Bollenstreek: ze geven kwekerijbedrijven toegang tot hun achterste percelen. — Lisse / bollengebied' WHERE slug = 'achterweg-zuid-2';
UPDATE locations SET full_description = 'De bollenpercelen langs de Achterweg Zuid worden in het bloeiseizoen een tapijt van kleur, met name wanneer tulpenrassen van verschillende kleuren naast elkaar staan. Dit type compositie is kenmerkend voor de visuele aantrekkingskracht van de Bollenstreek. — Lisse / westelijk bollengebied' WHERE slug = 'achterweg-zuid-3';
UPDATE locations SET full_description = 'Langs de Achterweg Zuid liggen bollenpercelen omgeven door sloten en windschermen. Het open veldlandschap hier is een stille, maar kleurrijke tegenhanger van het bekendere Heereweg-traject. — Lisse / westelijk bollengebied' WHERE slug = 'achterweg-zuid-4';
UPDATE locations SET full_description = 'De Achterweg Zuid vormt de westelijke grens van een intensief bollenteeltgebied in Lisse. Percelen langs deze weg wisselen elk seizoen van beplanting, waardoor het kleurlandschap jaar na jaar verandert. — Lisse / westelijk bollengebied' WHERE slug = 'achterweg-zuid-5';
UPDATE locations SET full_description = 'Rondom de Akervoorderlaan liggen percelen die grenzen aan de overgangszone tussen Sassenheim en Lisse, beide klassieke bollenteeltgebieden. De kalkrijke zandgrond hier maakt de omgeving geschikt voor een breed scala aan bolgewassen. — Lisse–Sassenheim / Akervoorde-zone' WHERE slug = 'akervoorderlaan-1';
UPDATE locations SET full_description = 'De Akervoorderlaan verwijst naar het historische buurtschap Akervoorde in dit deel van de Bollenstreek. De omgeving is al eeuwenlang agrarisch en vormt een van de stille hoeken van het bollenlandschap. — Lisse–Sassenheim / Akervoorde-zone' WHERE slug = 'akervoorderlaan-2';
UPDATE locations SET full_description = 'De Beeklaan in dit deel van Noordwijk doorsnijdt bollenakkers vlak bij de duinrand. De zandige, licht kalkrijke grond hier is bijzonder geschikt voor vroeg bloeiende bolgewassen zoals vroege tulpenrassen en wilde narcissen. — Noordwijk / duinzone' WHERE slug = 'beeklaan';
UPDATE locations SET full_description = 'De percelen rondom de Beeklaan in het noorden van Lisse zijn in gebruik als bollengrond en vormen een van de actieve teeltzones in dit deel van de Bollenstreek. Tulpen en lelies wisselen hier af per seizoen. — Lisse / Beeklaan-zone noord' WHERE slug = 'beeklaan-1';
UPDATE locations SET full_description = 'De Beeklaan in Lisse-Noord loopt langs een waterloop die vroeger dienstdeed voor de irrigatie en afwatering van bollenpercelen. Water was cruciaal in de Bollenstreek: te droog of te nat kon een hele oogst ruïneren. — Lisse / Beeklaan-zone noord' WHERE slug = 'beeklaan-2';
UPDATE locations SET full_description = 'De Boekhorsterweg in Noordwijkerhout verwijst naar de historische buitenplaats Boekhorst, een van de vele landgoederen die de Bollenstreek rijk is. De omgeving van dit lint combineert bollenteelt met de statige sfeer van historisch landgoedbeheer. — Noordwijkerhout / Boekhorst-zone' WHERE slug = 'boekhorsterweg';
UPDATE locations SET full_description = 'De bollenpercelen langs de Bronsgeesterweg zijn in het bloeiseizoen een kleurrijke aanvulling op de beter bekende routes in de Bollenstreek. Wie hier in april doorheen rijdt, ziet de tulpen in volle bloei langs weerszijden van de weg. — Noordwijk–Sassenheim / bollenzone' WHERE slug = 'bronsgeesterweg-1';
UPDATE locations SET full_description = 'Langs de Bronsgeesterweg zijn open bollenpercelen te zien met slootjes en windschermen die het teeltlandschap structureren. De rustige omgeving maakt dit lint populair bij fietsers die de drukke routes vermijden. — Noordwijk–Sassenheim / bollenzone' WHERE slug = 'bronsgeesterweg-2';
UPDATE locations SET full_description = 'De Bronsgeesterweg doorsnijdt een zone van klassieke bollenteelt tussen Noordwijk en Sassenheim. De naam verwijst mogelijk naar een historisch watergebruik of erf in dit agrarische lint. — Noordwijk–Sassenheim / bollenzone' WHERE slug = 'bronsgeesterweg-3';
UPDATE locations SET full_description = 'De Carolus Clusiuslaan is vernoemd naar de Vlaamse botanist Carolus Clusius, die in de zestiende eeuw als een van de eersten tulpen in de Nederlanden introduceerde. Zijn werk legde de basis voor de bloembollensector die de Bollenstreek groot maakte. — Sassenheim / historisch bollengebied' WHERE slug = 'carolus-clusiuslaan-1';
UPDATE locations SET full_description = 'De bollenpercelen rondom De Boender veranderen elk voorjaar van gedaante, naarmate tulpen en hyacinten openbloeien. Dit soort rustige linten in het buitengebied van Noordwijk zijn in het bloeiseizoen een bijzondere ontdekking. — Noordwijk / historisch buitengebied' WHERE slug = 'de-boender-1';
UPDATE locations SET full_description = 'De naam De Boender verwijst in het oud-Hollands naar een weg die werd gebruikt om vee van de ene naar de andere weide te drijven. In de Bollenstreek werden dit soort paden later in gebruik genomen als kavelpaden voor bollenland. — Noordwijk / historisch buitengebied' WHERE slug = 'de-boender-2';
UPDATE locations SET full_description = 'Langs de Delfweg is de overgang zichtbaar tussen de hogere geestgrond, geschikt voor bollenteelt, en de lagere veengebieden. Dit reliëfverschil bepaalt al eeuwenlang welk land als bollengrond en welk als weiland in gebruik is. — Lisse / overgangszone geest-polder' WHERE slug = 'delfweg-1';
UPDATE locations SET full_description = 'De Delfweg loopt door een gebied waar de teelt van bloembollen grenst aan lager gelegen polderpercelen. De naam ''delf'' verwijst naar een historische waterloop die de afwatering van dit teeltgebied regelde. — Lisse / westelijke polderrand' WHERE slug = 'delfweg-2';
UPDATE locations SET full_description = 'Aan het begin van Duinschoten zijn in april de bollenvelden op hun kleurrijkst, met rijen hyacinten en tulpen die de weg omlijsten. De ligging dicht bij het meer en de duinen maakt dit een bijzonder aangename plek om het bloeiseizoen te beleven. — Noordwijkerhout / duinrand-bollenzone' WHERE slug = 'duinschoten-1';
UPDATE locations SET full_description = 'De routes langs Duinschoten bieden fietsers een fraaie tocht door het bollengebied van Noordwijkerhout, vlak bij de meerplas en het bosgebied. In het bloeiseizoen is dit een van de meest schilderachtige routes in de regio. — Noordwijkerhout / duinrand-bollenzone' WHERE slug = 'duinschoten-2';
UPDATE locations SET full_description = 'De percelen langs Duinschoten maken deel uit van het actieve bollengebied rondom Noordwijkerhout, dat bekendstaat als een van de meest productiefste bollenregio''s in de hele Bollenstreek. Hier worden zowel tulpen als bijzondere soorten geteeld. — Noordwijkerhout / duinrand-bollenzone' WHERE slug = 'duinschoten-3';
UPDATE locations SET full_description = 'Duinschoten in Noordwijkerhout ligt in een zone waar de duinrand dichtbij het bollenland komt, met schitterend doorzicht over de bollenvelden en de duintop als achtergrond. De naam verwijst naar de bebossing van duingebied in de directe omgeving. — Noordwijkerhout / duinrand-bollenzone' WHERE slug = 'duinschoten-4';
UPDATE locations SET full_description = 'Aan het begin van de Duinweg zijn de eerste bollenbloemen in het seizoen al vroeg te spotten, aangewaaid door de zoute zeelucht van de nabijgelegen kust. Dit deel van Noordwijk is een van de vroegste bloeizones in de hele Bollenstreek. — Noordwijk / duinzone' WHERE slug = 'duinweg-1';
UPDATE locations SET full_description = 'De percelen langs de Duinweg profiteren van de beschutting van de duinen en de warme microklimaten die daardoor ontstaan. Dit maakt de zone geschikt voor vroegbloeiende bolgewassen zoals vroege tulpen en wilde narcissen. — Noordwijk / duinzone' WHERE slug = 'duinweg-2';
UPDATE locations SET full_description = 'De Duinweg in Noordwijk loopt evenwijdig aan de duinrand en biedt prachtige doorzichten over de overgangszone van zandduinen naar bollenakkers. Dit unieke landschapstype is alleen te vinden langs de kust van de Bollenstreek. — Noordwijk / duinzone' WHERE slug = 'duinweg-3';
UPDATE locations SET full_description = 'De Eikenhorstlaan ligt in een groene bufferzone tussen de bollenteeltgebieden en de historische kasteelomgeving van Teylingen. De combinatie van bomen, weiden en bollenpercelen maakt dit een landschappelijk afwisselende omgeving. — Sassenheim / kasteelrand' WHERE slug = 'eikenhorstlaan-1';
UPDATE locations SET full_description = 'De Essenlaan sluit aan op de grotere fietsroutes door de Bollenstreek en is een rustiger alternatief voor de drukte op de Heereweg. Het lint biedt een authentiek beeld van het werkende bollenlandschap. — Lisse / Essenlaan-lint' WHERE slug = 'essenlaan-1';
UPDATE locations SET full_description = 'In het voorjaar zijn de akkertjes langs de Essenlaan gevuld met tulpen en narcissen, terwijl de essen aan weerszijden van de weg uitlopen in frisch groen blad. De combinatie van bloeiende bollen en uitlopende bomen maakt dit een bijzonder voorjaarslint. — Lisse / Essenlaan-lint' WHERE slug = 'essenlaan-2';
UPDATE locations SET full_description = 'De Essenlaan in Lisse loopt door een groen lint met bollenpercelen en bomenrijen. De essen die de laan zijn naam gaven, zijn een verwijzing naar de inheemse beplanting die vroeger langs veel Bollenstreekwegen stond. — Lisse / Essenlaan-lint' WHERE slug = 'essenlaan-3';
UPDATE locations SET full_description = 'In de omgeving van de Frank van Borselenlaan worden tulpen- en hyacintenbollen geteeld op de kalkrijke zandgrond die kenmerkend is voor de Bollenstreek. De bloembollen die hier groeien worden wereldwijd geëxporteerd. — Sassenheim / noordelijk bollengebied' WHERE slug = 'frank-van-borselenlaan-1';
UPDATE locations SET full_description = 'Dit deel van de Bollenstreek trekt elk voorjaar honderdduizenden bezoekers die komen voor de kleurrijke bollenvelden. De Frank van Borselenlaan biedt rustige doorzichten over het open teeltlandschap. — Sassenheim / bollenroute' WHERE slug = 'frank-van-borselenlaan-2';
UPDATE locations SET full_description = 'Het gebied rondom de Frank van Borselenlaan kenmerkt zich door open bollenpercelen op geestgrond, afgewisseld met bomenrijen en kavelsloten. Dit open landschap is een van de meest fotogenieke aspecten van de Bollenstreek. — Sassenheim / bollengebied' WHERE slug = 'frank-van-borselenlaan-3';
UPDATE locations SET full_description = 'Langs dit deel van de Frank van Borselenlaan wisselen bollenpercelen elk seizoen van gewas, waardoor het kleurlandschap elk voorjaar anders oogt. Tulpen, narcissen en hyacinten volgen elkaar op in een eeuwenoud teeltritme. — Sassenheim / westelijke bollenrand' WHERE slug = 'frank-van-borselenlaan-4';
UPDATE locations SET full_description = 'De Frank van Borselenlaan loopt door een gebied waar zandrijke geestgrond al eeuwenlang geschikt is voor de teelt van tulpen en hyacinten. In het voorjaar kleuren de omliggende percelen in felrode, gele en paarse tinten. — Sassenheim / westelijke bollenrand' WHERE slug = 'frank-van-borselenlaan-5';
UPDATE locations SET full_description = 'De Gooweg in Noordwijk is een oud historisch pad in het bollengebied, waarvan de naam teruggaat op een middeleeuwse weginrichting. Langs dit type gooien of gemene wegen had iedereen in vroeger tijden recht van doorgang. — Noordwijk / historisch lint' WHERE slug = 'gooweg-1';
UPDATE locations SET full_description = 'Het noordelijke begin van de Heereweg in Lisse leidt richting Keukenhof, het wereldberoemde bloemenpark dat jaarlijks miljoenen bezoekers trekt. Deze route staat symbool voor de aantrekkingskracht van de Bollenstreek op het internationale toerisme. — Lisse / Heereweg nabij Keukenhof' WHERE slug = 'heereweg-lis-1';
UPDATE locations SET full_description = 'Langs dit gedeelte van de Heereweg liggen percelen die veelal worden bebouwd met verschillende tulpenrassen, waarbij elk ras een iets andere bloeitijd en kleur heeft. Dit geeft de akkers een gevarieerd beeld gedurende het hele bloeiseizoen. — Lisse / Heereweg-lint' WHERE slug = 'heereweg-lis-2';
UPDATE locations SET full_description = 'Dit deel van de Heereweg in Lisse maakt deel uit van een eeuwenoude route die de Bollenstreek-gemeenten met elkaar verbond. Langs dit traject werden vroeger bollen met paard en wagen naar sorteerderijen vervoerd. — Lisse / Heereweg-lint' WHERE slug = 'heereweg-lis-3';
UPDATE locations SET full_description = 'Op de Heereweg in Lisse begint het bloeiseizoen al vroeg, wanneer de eerste narcissen in maart hun witte en gele koppen opsteken. Tot in mei volgen dan tulpen, hyacinten en andere bolgewassen in onafgebroken kleurenpracht. — Lisse / Heereweg-lint' WHERE slug = 'heereweg-lis-4';
UPDATE locations SET full_description = 'De Heereweg in Lisse biedt lange, open zichtlijnen over de bollenvelden richting de duinen. In het bloeiseizoen zijn de kleurstroken van rood, geel, wit en paars een van de meest fotografeerde landschapsbeelden van Nederland. — Lisse / Heereweg-lint' WHERE slug = 'heereweg-lis-5';
UPDATE locations SET full_description = 'Langs de Heereweg in Lisse zijn aan weerszijden bollenpercelen te zien die intensief in gebruik zijn voor de teelt van tulpen, hyacinten en lelies. De Heereweg doorkruist het hart van het meest productieve bollengebied van Nederland. — Lisse / Heereweg-lint' WHERE slug = 'heereweg-lis-6';
UPDATE locations SET full_description = 'De Heereweg is de meest iconische ader door het bollengebied van Lisse en trekt elk voorjaar grote aantallen bezoekers. Dit zuidelijke deel van de Heereweg biedt een rustigere beleving van de bollenvelden dan het drukke Keukenhof-gedeelte. — Lisse / Heereweg-lint zuidelijk' WHERE slug = 'heereweg-lis-7';
UPDATE locations SET full_description = 'De Heereweg is de meest iconische route door het bollengebied van Lisse en één van de meest gefotografeerde wegen in de Bollenstreek. In het bloeiseizoen rijden hier dagelijks duizenden bezoekers langs de bloeiende velden. — Lisse / Heereweg-lint' WHERE slug = 'heereweg-lis-8';
UPDATE locations SET full_description = 'Het zuidelijke deel van de Herenweg in Noordwijk vormt een toegangsroute naar het bollenvelden-landschap vanuit het dorp. Dit lint sluit aan op de populaire bollenroutes richting Lisse en Keukenhof. — Noordwijk / bollenroute' WHERE slug = 'herenweg-nw-1';
UPDATE locations SET full_description = 'Langs de Herenweg in Noordwijk zijn in april de bollenvelden een feest van kleur. Wielerliefhebbers en wandelaars die dit traject volgen, lopen of rijden door een van de meest indrukwekkende bloeizones van de kust-Bollenstreek. — Noordwijk / Herenweg-lint' WHERE slug = 'herenweg-nw-2';
UPDATE locations SET full_description = 'De Herenweg in het buitengebied van Noordwijk loopt door een klassiek bollengebied op de westelijke flank van de Bollenstreek. De lichte, kalkrijke zandgrond hier is van nature uitstekend geschikt voor tulpen- en narcissenteelt. — Noordwijk / Herenweg-lint' WHERE slug = 'herenweg-nw-3';
UPDATE locations SET full_description = 'Aan het begin van Het Laantje zijn in het voorjaar de eerste bolbloemen al vroeg te zien. De nabijheid van de duinen zorgt voor een warmere microklimaat, waardoor bollen hier soms eerder bloeien dan in de polders. — Noordwijk / duinrandbollenvelden' WHERE slug = 'het-laantje-1';
UPDATE locations SET full_description = 'Dit deel van Het Laantje biedt doorzichten over kleine bollenpercelen die ingeklemd liggen tussen duin en bebouwing. Het kleinschalige karakter van dit lint is een stille tegenhanger van de grotere bollengebieden in de regio. — Noordwijk / duinrandbollenvelden' WHERE slug = 'het-laantje-2';
UPDATE locations SET full_description = 'Het Laantje in Noordwijk is een smal, rustig pad door het bollenvelden- en duinenlandschap. Wandelaars die hier in het bloeiseizoen komen, beleven de Bollenstreek op haar meest authentiek en stil. — Noordwijk / duinrandbollenvelden' WHERE slug = 'het-laantje-3';
UPDATE locations SET full_description = 'De Hoogduinweg biedt een unieke combinatie van duinlandschap en bollenteelt op relatief korte afstand. Fietsers en wandelaars die dit traject volgen, beleven zowel de stilte van de duinen als het kleurspektakel van de bollenvelden. — Lisse / binnenduinrand' WHERE slug = 'hoogduinweg-1';
UPDATE locations SET full_description = 'De percelen langs de Hoogduinweg grenzen aan de duinvoet en hebben een lossere, kalkrijke bodemstructuur die ideaal is voor tulpenteelt. Juist op de overgang van duin naar polder gedijen veel bolgewassen uitstekend. — Lisse / binnenduinrand' WHERE slug = 'hoogduinweg-2';
UPDATE locations SET full_description = 'De Hoogduinweg loopt langs de binnenduinrand van de Bollenstreek, de zone waar zandduinen geleidelijk overgaan in bollenakkers. Deze overgangszone is landschappelijk gezien een van de meest dynamische delen van de streek. — Lisse / binnenduinrand' WHERE slug = 'hoogduinweg-3';
UPDATE locations SET full_description = 'De Jacoba van Beierenweg vormt een populaire fiets- en wandelroute door de Bollenstreek. In het bloeiseizoen biedt het traject prachtige zichtlijnen over kleurrijke bollenvelden richting de duinen. — Sassenheim / bollenroute' WHERE slug = 'jacoba-van-beierenweg-1';
UPDATE locations SET full_description = 'Langs de Jacoba van Beierenweg liggen percelen die voor een groot deel in gebruik zijn als bollengrond. De omgeving behoort tot de klassieke teeltzone van Sassenheim, waar tulpen en hyacinten al generaties worden geteeld. — Sassenheim / historisch ontginningsgebied' WHERE slug = 'jacoba-van-beierenweg-2';
UPDATE locations SET full_description = 'De Jacoba van Beierenweg is vernoemd naar de beroemde gravin van Holland die in de vijftiende eeuw de streek beheerste. Het landschap langs deze weg heeft een directe verbinding met de middeleeuwse agrarische ontginningsgeschiedenis van de Bollenstreek. — Sassenheim / historisch ontginningsgebied' WHERE slug = 'jacoba-van-beierenweg-3';
UPDATE locations SET full_description = 'De Johan Speelmanweg is vernoemd naar een historische figuur verbonden aan de regio, een verwijzing naar het rijke naamgeving-erfgoed van de Bollenstreek. De weg loopt door een zone waar bollenkwekerijen hun wortels in de vroege twintigste eeuw hebben. — Lisse / historisch bollengebied' WHERE slug = 'johan-speelmanweg-1';
UPDATE locations SET full_description = 'De Kraaierslaan in Noordwijk loopt langs het duingebied en biedt een rustige fietsverbinding door de overgangszone van duin en bollenland. In het bloeiseizoen zijn hier bollenvelden te zien met de duinkam als achtergrond. — Noordwijk / duinrandbollenvelden' WHERE slug = 'kraaierslaan';
UPDATE locations SET full_description = 'De Langervelderlaan verbindt het dorp Noordwijk met het recreatieve duingebied van Langeveld en loopt daarmee door een bijzondere overgangszone van bollenteelt en natuur. Dit lint biedt één van de fraaiste combinatiebelevingen in de Bollenstreek. — Noordwijk / Langevelde-zone' WHERE slug = 'langervelderlaan';
UPDATE locations SET full_description = 'De Langervelderweg slingert langs de duinvoet van de Langevelderse Duinen, met bollenvelden aan de ene en stuifduinen aan de andere zijde. Dit contrast tussen natuur en teelt is een van de meest karakteristieke beelden van de Noordwijkse Bollenstreek. — Noordwijk / Langevelde-zone' WHERE slug = 'langervelderweg';
UPDATE locations SET full_description = 'De Langervelderweg loopt langs de Langevelderduinen, een fraai duingebied dat aansluit op het bollenlandschap van Noordwijk. Het lint biedt een bijzondere combinatie van natuur en teelt op relatief korte afstand. — Noordwijk / Langevelde-zone' WHERE slug = 'langervelderweg-2';
UPDATE locations SET full_description = 'Het beginpunt van de Leeweg vormt een prettige start voor fietsers die de bollenvelden van Noordwijk-Sassenheim willen verkennen. Langs dit traject zijn weinig toeristen, maar volop bollenpracht te vinden. — Sassenheim / Leeweg-start' WHERE slug = 'leeweg-1';
UPDATE locations SET full_description = 'De Leeweg verbindt de bollenpercelen in het binnengebied met de bredere doorgaande wegen in de Bollenstreek. Dit type directe ontsluitingslint maakt het logistieke systeem van de bloembollensector slagvaardig. — Noordwijk–Sassenheim / Leeweg-lint' WHERE slug = 'leeweg-2';
UPDATE locations SET full_description = 'De Leeweg is een van de oudere verkavelingslinten in dit deel van de Bollenstreek, gelegen op de hogere geestrug. Langs dit soort wegen zijn bollenkwekers al generaties lang actief, soms met familiebedrijven die meer dan een eeuw oud zijn. — Noordwijk–Sassenheim / Leeweg-lint' WHERE slug = 'leeweg-3';
UPDATE locations SET full_description = 'In april en mei staan de percelen langs de Leeweg op hun prachtigst, met rijen bloeiende tulpen die de horizon kleuren. De vroege ochtendlichten creëren hier een bijzondere fotogenieke sfeer over de bollenvelden. — Noordwijk–Sassenheim / Leeweg-lint' WHERE slug = 'leeweg-4';
UPDATE locations SET full_description = 'Langs de Leeweg opent het landschap zich naar weerszijden in uitgestrekte bollenvelden. De combinatie van open akkers, smalle sloten en een recht lint is typerend voor het geestlandschap in dit deel van de Bollenstreek. — Noordwijk–Sassenheim / Leeweg-lint' WHERE slug = 'leeweg-5';
UPDATE locations SET full_description = 'De Leeweg loopt door een van de meest actieve bollenteeltzones tussen Noordwijk en Sassenheim. Percelen langs dit lint wisselen elk seizoen van gewas, met tulpen, hyacinten en lelies als meest voorkomende gewassen. — Noordwijk–Sassenheim / Leeweg-lint' WHERE slug = 'leeweg-6';
UPDATE locations SET full_description = 'Aan het begin van de Leidsestraat richting Lisse-centrum zijn in het voorjaar de kleurrijke bollenvelden in de omgeving goed te ruiken en te zien. Hyacinten staan bekend om hun sterke geur die al van verre te ruiken is. — Lisse / dorpslint' WHERE slug = 'leidsestraat-1';
UPDATE locations SET full_description = 'Rondom de Leidsestraat in Lisse liggen bollenpercelen op de typische lichte zandgrond van de geestrug. Dit gebied vormt het hart van de Bollenstreek, de wereldwijde exportregio voor bloembollen. — Lisse / dorpslint' WHERE slug = 'leidsestraat-2';
UPDATE locations SET full_description = 'De Leidsestraat in Lisse is van oudsher een verbindingsader tussen het dorp en de omliggende bollengebieden. Via routes als deze werden bloembollen naar sorteer- en veilingbedrijven vervoerd. — Lisse / dorpslint' WHERE slug = 'leidsestraat-3';
UPDATE locations SET full_description = 'Het zuidelijke deel van de Leidsevaart grenst aan het rustige buitengebied van Sassenheim, een ideale plek voor een stille tocht langs het water. Van hieruit zijn in het bloeiseizoen bollenvelden te zien die de vaart omzomen. — Sassenheim / Leidsevaart-lint' WHERE slug = 'leidsevaart-1';
UPDATE locations SET full_description = 'In het voorjaar weerspiegelen de bloeiende bollenvelden soms in de Leidsevaart, een idyllisch beeld dat typerend is voor de Bollenstreek. De rustige oevers zijn een geliefde plek voor wandelaars en fotografen. — Sassenheim / Leidsevaart-lint' WHERE slug = 'leidsevaart-2';
UPDATE locations SET full_description = 'De oevers van de Leidsevaart bieden een gevarieerd landschapsbeeld met riet, wilgen en bollenpercelen die tot aan het water doorlopen. Dit type oeverzone is een bijzondere mix van natuur en agrarisch gebruik. — Sassenheim / Leidsevaart-lint' WHERE slug = 'leidsevaart-3';
UPDATE locations SET full_description = 'Langs de Leidsevaart zijn nog sporen te vinden van de voormalige trekvaartcultuur, waarbij schuiten door de vaart werden gevaren om goederen te transporteren. Dit systeem was in de zeventiende en achttiende eeuw cruciaal voor de Bollenstreek. — Sassenheim / Leidsevaart-lint' WHERE slug = 'leidsevaart-4';
UPDATE locations SET full_description = 'De Leidsevaart is een van de oudste en meest gebruikte waterwegen in de Bollenstreek en diende eeuwenlang voor het transport van goederen tussen Leiden en Haarlem, inclusief bloembollen. De vaart is een historische pijler van de regionale economie. — Sassenheim / Leidsevaart-lint' WHERE slug = 'leidsevaart-5';
UPDATE locations SET full_description = 'Het beginpunt van de Loosterweg is een geliefde startplaats voor fietsers die de bollenvelden van Lisse willen verkennen. De weg biedt een rustige, authentieke route door het hart van het bloembollenbedrijf. — Lisse / Loosterweg-lint' WHERE slug = 'loosterweg-1';
UPDATE locations SET full_description = 'De Loosterweg verbond vroeger de kweekpercelen in het binnengebied met de grotere ontsluitingswegen richting Lisse-centrum. Langs dit lint zijn nog sporen van oude kavelpaden en droogovens zichtbaar. — Lisse / Loosterweg-lint' WHERE slug = 'loosterweg-2';
UPDATE locations SET full_description = 'Halverwege de Loosterweg in Lisse ontvouwt zich in april een breed kleurenpanorama van bloeiende tulpen. De verschillende rassen bloeien in golven na elkaar, waardoor het landschap enkele weken lang in beweging lijkt. — Lisse / Loosterweg-lint' WHERE slug = 'loosterweg-3';
UPDATE locations SET full_description = 'Langs de Loosterweg in Lisse opent het landschap zich richting uitgestrekte bollenvelden met af en toe een bollenschuur als blikvanger. Dit type werklandschap is een stille maar indrukwekkende representatie van de bloembollensector. — Lisse / Loosterweg-lint' WHERE slug = 'loosterweg-4';
UPDATE locations SET full_description = 'De Loosterweg is het moedertraject van de Loosterweg-familie en loopt recht door het bollengebied van Lisse. Dit klassieke lint staat symbool voor het fijne ontsluiting dat de Bollenstreek kenmerkt. — Lisse / Loosterweg-lint' WHERE slug = 'loosterweg-5';
UPDATE locations SET full_description = 'De Loosterweg fungeerde historisch als verbindingsroute voor bollenkwekers die hun percelen moesten bereiken vanuit het dorp. Het netwerk van Loosterwegen in Lisse is een goed bewaard voorbeeld van de functionele indeling van het bollenlandschap. — Lisse / Loosterweg-lint' WHERE slug = 'loosterweg-noord-1';
UPDATE locations SET full_description = 'In de vroege ochtend, wanneer de zon laag staat, creëren de bollenvelden langs de Loosterweg Noord een spectaculair lichtspel over de kleurige rijen bloemen. Dit deel van Lisse is in het bloeiseizoen bijzonder fotogeniek. — Lisse / Loosterweg-lint' WHERE slug = 'loosterweg-noord-2';
UPDATE locations SET full_description = 'Langs de Loosterweg Noord zijn de bollenpercelen omzoomd door smalle sloten en windsingels, typerend voor het weideachtige bollenlandschap van de Bollenstreek. De kleurrijke akkers zijn in april zichtbaar tot aan de horizon. — Lisse / Loosterweg-lint' WHERE slug = 'loosterweg-noord-3';
UPDATE locations SET full_description = 'Het Loosterweg-lint is een van de langste aaneengesloten bollenteeltstroken in Lisse, met percelen die seizoensgewijs worden beplant met tulpen, narcissen en andere bolgewassen. De Loosterweg staat bekend als klassiek bollenpad. — Lisse / Loosterweg-lint' WHERE slug = 'loosterweg-noord-4';
UPDATE locations SET full_description = 'De Loosterweg Zuid is een rustige route voor fietsers die de bollenvelden van Lisse willen verkennen zonder de drukte van de Heereweg. Langs dit lint is de alledaagse kant van de bollenteelt goed zichtbaar. — Lisse / Loosterweg-netwerk zuidelijk' WHERE slug = 'loosterweg-zuid-1';
UPDATE locations SET full_description = 'Langs de Loosterweg Zuid zijn open akkers te zien met zichtlijnen richting het binnenduin. Het open karakter van dit landschap herinnert aan het oorspronkelijke geestlandschap waarop de Bollenstreek is gebouwd. — Lisse / Loosterweg-netwerk zuidelijk' WHERE slug = 'loosterweg-zuid-2';
UPDATE locations SET full_description = 'De Loosterweg Zuid is een directe verbinding door het zuidelijke bollengebied van Lisse, met percelen die grotendeels in gebruik zijn voor de teelt van tulpen en narcissen. Dit lint maakt deel uit van het uitgebreide Loosterweg-netwerk in de regio. — Lisse / Loosterweg-netwerk zuidelijk' WHERE slug = 'loosterweg-zuid-3';
UPDATE locations SET full_description = 'De Nieuwe Zeeweg in Noordwijk verbindt het bollengebied met de kuststrook, wat dit traject bijzonder maakt voor toeristen die strand én bollenvelden willen combineren. Langs deze weg is de duinrand als groene achtergrond zichtbaar. — Noordwijk / kust-bollenzone' WHERE slug = 'nieuwe-zeeweg';
UPDATE locations SET full_description = 'De percelen langs de Nieuweweg behoren tot de buitenste teeltzones van Hillegom, waar bollenkwekers grond in gebruik hebben genomen naarmate de vraag naar bloembollen groeide. De Bollenstreek breidde haar teeltoppervlak in de twintigste eeuw flink uit. — Hillegom / randgebied' WHERE slug = 'nieuweweg-1';
UPDATE locations SET full_description = 'De Nieuweweg in Hillegom-Noord sluit aan op doorgaande routes richting Lisse en Noordwijkerhout en vormt een verbinding in het toeristische fietsnetwerk van de Bollenstreek. Rondom dit lint zijn kleurrijke velden te zien in het bloeiseizoen. — Hillegom / noord' WHERE slug = 'nieuweweg-2';
UPDATE locations SET full_description = 'Langs de Noorder Leidsevaart zijn in het voorjaar narcissenvelden een van de eerste signalen van het naderende bloeiseizoen. Narcissen bloeien vroeger dan tulpen en kondigen zo het kleurrijke seizoen aan. — Hillegom / Leidsevaart-lint' WHERE slug = 'noorder-leidsevaart-1';
UPDATE locations SET full_description = 'De oevers van de Noorder Leidsevaart bieden een rustige groene omlijsting voor de omliggende bollenvelden. In het bloeiseizoen weerspiegelen de kleurrijke akkers in het water van de vaart. — Hillegom / Leidsevaart-lint' WHERE slug = 'noorder-leidsevaart-2';
UPDATE locations SET full_description = 'Dit deel van de Noorder Leidsevaart loopt door een van de oudste agrarische zones van Hillegom, waar de bodem door eeuwen van bollenteelt en bemesting een specifiek karakter heeft gekregen. De vaart werd gegraven om de waterhuishouding van de regio te beheersen. — Hillegom / Leidsevaart-lint' WHERE slug = 'noorder-leidsevaart-3';
UPDATE locations SET full_description = 'De Noorder Leidsevaart is het noordelijke deel van de historische vaarverbinding die de Bollenstreek doorkruist. De vaart diende eeuwenlang voor de afvoer van agrarische producten, waaronder bloembollen, vanuit het achterland naar de kust. — Hillegom / Leidsevaart-zone' WHERE slug = 'noorder-leidsevaart-4';
UPDATE locations SET full_description = 'De naam Northgodreef verwijst naar een historische dreef in het buitengebied van Noordwijk, een type weg dat oorspronkelijk diende voor het drijven van vee. De omgeving is later omgezet in bollenland, een transformatie die in de Bollenstreek vaker plaatsvond. — Noordwijk / historisch buitengebied' WHERE slug = 'northgodreef';
UPDATE locations SET full_description = 'Oosterduinen 1 markeert de start van een populaire fietsroute die het bollengebied van Noordwijkerhout verbindt met de meerplas en het duingebied. In het bloeiseizoen biedt deze route een unieke combinatie van natuur en bollenpracht. — Noordwijkerhout / Oosterduinen-zone' WHERE slug = 'oosterduinen-1';
UPDATE locations SET full_description = 'De percelen rondom Oosterduinen worden beplant met bolgewassen die profiteren van de beschutting van de nabijgelegen duinen. Dit microklimaat zorgt voor iets warmere en drogere groeiomstandigheden, gunstig voor de vroegst bloeiende rassen. — Noordwijkerhout / Oosterduinen-zone' WHERE slug = 'oosterduinen-2';
UPDATE locations SET full_description = 'Oosterduinen in Noordwijkerhout ligt aan de oostzijde van het duingebied en biedt fraaie doorzichten over bollenvelden richting het meer. Het lint vormt een schakel tussen duinnatuur en actief bollenland. — Noordwijkerhout / Oosterduinen-zone' WHERE slug = 'oosterduinen-3';
UPDATE locations SET full_description = 'Het begin van de Oude Herenweg sluit aan op routes vanuit Sassenheim richting de bollenvelden van Lisse. Dit lint geeft een authentiek, minder druk beeld van de Bollenstreek dan de grote doorgaande wegen. — Sassenheim / bollenrand' WHERE slug = 'oude-herenweg-1';
UPDATE locations SET full_description = 'In het bloeiseizoen zijn de akkers langs de Oude Herenweg een lust voor het oog, met rijen tulpen en narcissen die het oude lint omlijsten. De route is populair bij fietsers die de bollenvelden rustig willen verkennen. — Sassenheim–Lisse / historisch lint' WHERE slug = 'oude-herenweg-2';
UPDATE locations SET full_description = 'De percelen langs de Oude Herenweg worden al generaties lang beplant met bolgewassen, van tulpen tot lelies. De zandgrond in dit deel van de Bollenstreek is van nature geschikt voor een brede waaier aan bloembolsoorten. — Sassenheim–Lisse / bollenzone' WHERE slug = 'oude-herenweg-3';
UPDATE locations SET full_description = 'Langs de Oude Herenweg wisselen bollenpercelen af met restanten van het historische lintbebouwingspatroon, met hier en daar een oude bollenschuur of fruitboom. Dit lint heeft een rustiger karakter dan de drukke Heereweg. — Sassenheim–Lisse / historisch lint' WHERE slug = 'oude-herenweg-4';
UPDATE locations SET full_description = 'De Oude Herenweg is een van de oorspronkelijke doorgaande routes die vóór de aanleg van de modernere Heereweg door de Bollenstreek liep. Dit pad verbond nederzettingen en landgoederen al voor de opkomst van de bollenteelt. — Sassenheim–Lisse / historisch lint' WHERE slug = 'oude-herenweg-5';
UPDATE locations SET full_description = 'Aan het begin van de Pastoorslaan is in het vroege voorjaar al de geur van bloeiende hyacinten uit de omgeving te ruiken. Hillegom staat bekend om zijn uitgebreide hyacintenteelt, waarbij de bloemen in rijen van intense kleuren staan. — Hillegom / bollenteeltzone' WHERE slug = 'pastoorslaan-1';
UPDATE locations SET full_description = 'In de directe omgeving van de Pastoorslaan in Hillegom worden bloembollen geteeld op de voor de Bollenstreek typische lichte zandgrond. Hillegom is een van de kerngebieden voor de teelt en export van tulpen en narcissen. — Hillegom / bollenteeltzone' WHERE slug = 'pastoorslaan-2';
UPDATE locations SET full_description = 'De Pastoorslaan in Hillegom herinnert aan de historische rol van de kerk in de plattelandsgemeenschappen van de Bollenstreek. De omgeving is eeuwenlang agrarisch geweest en is later onderdeel geworden van het bloembollenkweekgebied. — Hillegom / dorpsrand' WHERE slug = 'pastoorslaan-3';
UPDATE locations SET full_description = 'Wegen als de Prinsenweg speelden een belangrijke rol in het transport van bloembollen naar sorteer- en exportbedrijven in de regio. De Bollenstreek groeide dankzij dit fijne netwerk van kavelpaden en ontsluitingswegen uit tot een wereldspeler. — Sassenheim / Prinsenweg-lint' WHERE slug = 'prinsenweg-1';
UPDATE locations SET full_description = 'De Prinsenweg vormt een rustige fietsvriendelijke route door het hart van de Bollenstreek. Wie hier in het voorjaar rijdt, heeft vaak zichtlijnen over uitgestrekte bollenvelden aan weerszijden van de weg. — Sassenheim / Prinsenweg-lint' WHERE slug = 'prinsenweg-2';
UPDATE locations SET full_description = 'Langs de Prinsenweg kleuren de bollenvelden in april en mei in felle tinten, afhankelijk van het geteelde gewas dat jaar. Narcissen bloeien hier vaak al vroeg in het seizoen, gevolgd door tulpen en hyacinten. — Sassenheim / Prinsenweg-lint' WHERE slug = 'prinsenweg-3';
UPDATE locations SET full_description = 'De Prinsenweg doorsnijdt een bollengebied dat al in de negentiende eeuw in gebruik was voor de teelt van bloembollen. De kalkrijke, goed doorlatende zandgrond maakt dit lint tot een klassieke kweekomgeving. — Sassenheim / Prinsenweg-lint' WHERE slug = 'prinsenweg-4';
UPDATE locations SET full_description = 'Het zuidelijke begin van de Provincialeweg in dit deel van de Bollenstreek markeert de historische grens tussen het teeltgebied van Hillegom en Lisse. Beide gemeenten hebben een rijke bollentraditie die teruggaat tot de zestiende eeuw. — Hillegom / grenszone Lisse' WHERE slug = 'provincialeweg-1';
UPDATE locations SET full_description = 'Dit traject van de Provincialeweg loopt langs klassieke bollenteeltpercelen op de overgang van geest naar polder. De grondgesteldheid varieert hier sterk op korte afstand, wat zichtbaar is in het wisselende gewas per perceel. — Hillegom / Provincialeweg-lint' WHERE slug = 'provincialeweg-2';
UPDATE locations SET full_description = 'Langs de Provincialeweg zijn in het bloeiseizoen de versgekopte bollenvelden te zien, een verrassend maar kenmerkend beeld in de Bollenstreek. Bollentelers verwijderen de bloemknoppen zodat de bol zijn energie naar groei kan richten. — Hillegom / Provincialeweg-lint' WHERE slug = 'provincialeweg-3';
UPDATE locations SET full_description = 'De Provinciale Weg vormt een belangrijke ontsluitingsas voor de Bollenstreek en verbindt de bollendorpen Lisse, Hillegom en Noordwijkerhout met elkaar. Langs deze weg zijn exportbedrijven en bloembollenkwekerijen gevestigd. — Hillegom / Provincialeweg-lint' WHERE slug = 'provincialeweg-4';
UPDATE locations SET full_description = 'De omgeving van de Schippersvaartweg kenmerkt zich door open bollenland met sloten en kavelinrichting die teruggaan op de middeleeuwse ontginning van het geestgebied. Het weids uitzicht geeft een helder beeld van het historische teeltlandschap. — Lisse / vaartzone' WHERE slug = 'schippersvaartweg-1';
UPDATE locations SET full_description = 'De Schippersvaartweg verwijst in de naam naar de historische vaart- en schipperscultuur die in dit deel van de Bollenstreek bestond. Via dit type routes werden bloembollen en agrarische producten per boot of as naar de markt gebracht. — Lisse / vaartzone' WHERE slug = 'schippersvaartweg-2';
UPDATE locations SET full_description = 'De kalkrijke schelpengrond langs de Schulpweg is van nature bijzonder geschikt voor de teelt van tulpen en hyacinten. Bollenkwekers kozen dit type grond bewust voor de hoogste opbrengst en kwaliteit van hun bollen. — Noordwijk / duinrandzone' WHERE slug = 'schulpweg-1';
UPDATE locations SET full_description = 'De Schulpweg in Noordwijk loopt langs de binnenduinrand, waar schelpengrond en zand de typische Bollenstreekbodem vormen. De naam ''Schulp'' verwijst naar de schelpenrijke kalkgrond die hier van nature voorkomt en ideaal is voor bollenteelt. — Noordwijk / duinrandzone' WHERE slug = 'schulpweg-2';
UPDATE locations SET full_description = 'Het westelijke deel van de ''s-Gravendamseweg ligt aan de rand van het bollenteeltgebied, waar percelen worden beplant afhankelijk van de grondsoort en waterstand. De variatie in grondtype zorgt voor een gevarieerd teeltaanbod per perceel. — Sassenheim / westrand' WHERE slug = 'sgravendamseweg-1';
UPDATE locations SET full_description = 'De ''s-Gravendamseweg doorkruist een zone aan de westrand van de Bollenstreek, waar de geestgrond geleidelijk overgaat in lager poldergebied. Deze overgang is ecologisch interessant en ook in het bollenlandschap goed zichtbaar. — Sassenheim / westrand' WHERE slug = 'sgravendamseweg-2';
UPDATE locations SET full_description = 'De ''s-Gravendamseweg verwijst naar ''s-Gravendam, een historisch buurtschap in de Bollenstreek. De weg liep vroeger naar een dam die het water in de polders reguleerde, een kenmerkend element in het door waterbeheer bepaalde landschap. — Sassenheim / ''s-Gravendam-zone' WHERE slug = 'sgravendamseweg-3';
UPDATE locations SET full_description = 'In de lente zijn de akkertjes langs de Spekkenlaan gevuld met bloeiende bolgewassen die elk perceel een eigen kleur geven. De kleine schaal van dit landschap maakt het bijzonder aangenaam om te fietsen. — Lisse / kleinschalig bollengebied' WHERE slug = 'spekkenlaan-1';
UPDATE locations SET full_description = 'De Spekkenlaan doorsnijdt een zone van kleinschalige bollenpercelen met sloten en erfbeplanting. Dit type lanen biedt een intiem beeld van de Bollenstreek, ver van de grote toeristische drukte. — Lisse / kleinschalig bollengebied' WHERE slug = 'spekkenlaan-2';
UPDATE locations SET full_description = 'De Stationsweg in Lisse herinnert aan het vroegere treinstation, van waaruit bloembollen en andere producten per spoor naar exportpunten werden vervoerd. Het spoor speelde een sleutelrol in de groei van de bollensector in de negentiende en twintigste eeuw. — Lisse / stationszone' WHERE slug = 'stationsweg-1';
UPDATE locations SET full_description = 'Langs de Teylingenlaan is de overgang zichtbaar tussen het open bollengebied en het parkachtige landgoedenlandschap rondom Teylingen. Linden- en kastanjelanen vormen hier een fraaie afwisseling met de vlakke bollenvelden. — Sassenheim / Teylingenzone' WHERE slug = 'teylingenlaan-2';
UPDATE locations SET full_description = 'De Teylingenlaan ligt in de directe omgeving van de historische kasteelzone van Teylingen. De laan verbindt het agrarische bollenlandschap met het groene parkgebied rondom de kasteelruïne. — Sassenheim / Teylingenzone' WHERE slug = 'teylingenlaan-3';
UPDATE locations SET full_description = 'Dit deel van de Teylingerdreef loopt in de schaduw van de historische invloedsfeer van kasteel Teylingen, ooit een strategisch bolwerk in het Hollandse duinenlandschap. De directe omgeving is eeuwenlang agrarisch beheerd en later deels overgenomen door bollenteelt. — Sassenheim / Teylingenzone' WHERE slug = 'teylingerdreef-1';
UPDATE locations SET full_description = 'De naam Teylingerdreef verwijst naar kasteel Teylingen, een middeleeuws slot in de buurt waarvan de ruïne nog altijd in het landschap staat. De omgeving heeft een rijke geschiedenis die teruggaat tot de Hollandse graven. — Sassenheim / Teylingenzone' WHERE slug = 'teylingerdreef-2';
UPDATE locations SET full_description = 'De Teylingerlaan vormt een mooie verbinding tussen het dorpscentrum van Sassenheim en het buitengebied richting Lisse. Bezoekers die deze laan bewandelen, komen langs bollenvelden met het silhouet van kasteelruïne Teylingen op de achtergrond. — Sassenheim / Teylingenzone' WHERE slug = 'teylingerlaan-1';
UPDATE locations SET full_description = 'Aan dit einde van de Van den Berch van Heemstedeweg liggen percelen die grenzen aan een overgangszone tussen historisch landgoedgebied en actieve bollenteelt. De combinatie van lanen en open velden geeft de omgeving een bijzonder karakter. — Sassenheim / landgoedrand' WHERE slug = 'van-den-berch-van-heemstedeweg-1';
UPDATE locations SET full_description = 'De Van den Berch van Heemstedeweg is vernoemd naar een adellijke familie die eeuwenlang verbonden was aan het Sassenheimse landgoedenlandschap. De omgeving vormt de overgang tussen oud buitengoedgebied en de klassieke bollenkweekzone van de Bollenstreek. — Sassenheim / landgoedrand' WHERE slug = 'van-den-berch-van-heemstedeweg-2';
UPDATE locations SET full_description = 'Rondom de Van Lyndenweg wisselen bollenpercelen af met doorkijkjes naar bredere akkers in de omgeving. De lichte zandgrond hier is van dezelfde kwaliteit als die langs de Heereweg, al is dit deel van Lisse minder bekend bij toeristen. — Lisse / binnengebied' WHERE slug = 'van-lyndenweg-1';
UPDATE locations SET full_description = 'De Van Lyndenweg herinnert aan de adellijke familie Van Lynden, die in vroeger tijden verbonden was aan de Bollenstreek als grondbezitter. Langs dit lint zijn sporen te vinden van de historische landgoedcultuur die de regio mede vormgaf. — Lisse / historisch lint' WHERE slug = 'van-lyndenweg-2';
UPDATE locations SET full_description = 'De Veenenburgerlaan vormt een populaire etappe op de fietsroutes door de Bollenstreek die Keukenhof verbinden met de omliggende bollendorpen. Langs deze weg zijn in het bloeiseizoen soms bijzondere soorten te spotten. — Lisse / bollenroute' WHERE slug = 'veenenburgerlaan-1';
UPDATE locations SET full_description = 'De omgeving van de Veenenburgerlaan behoort tot het kerngebied van de Lisser bollenteelt, waar zowel tulpen, lelies als bijzondere soorten worden gekweekt. De bollen worden na de oogst gedroogd, gesorteerd en wereldwijd verscheept. — Lisse / bollenteeltzone' WHERE slug = 'veenenburgerlaan-2';
UPDATE locations SET full_description = 'In april en mei staan de bollenpercelen langs de Veenenburgerlaan op hun mooist, met rijen tulpen en hyacinten in felle kleuren. Bollentelers koppen de bloemen af zodra ze in volle bloei staan, zodat de bol sterker wordt. — Lisse / Veenenburglaan-zone' WHERE slug = 'veenenburgerlaan-3';
UPDATE locations SET full_description = 'Dit deel van de Veenenburgerlaan biedt een prachtig doorzicht over de open bollenakkers met op de achtergrond de contouren van bomensingels en buitenplaatsen. In het bloeiseizoen is dit een van de fraaiste uitzichtpunten in Lisse. — Lisse / Veenenburglaan-zone' WHERE slug = 'veenenburgerlaan-4';
UPDATE locations SET full_description = 'De Veenenburgerlaan verwijst naar de historische buitenplaats Veenenburg, een van de vele landgoederen in de Bollenstreek die getuigen van de rijkdom die de bollenhandel genereerde. De omgeving combineert buitenplaatsgeschiedenis met actieve bollenteelt. — Lisse / Veenenburglaan-zone' WHERE slug = 'veenenburgerlaan-5';
UPDATE locations SET full_description = 'De Via Nova biedt fietsers een rustige doortocht door het bollengebied van Lisse-Noord, met open zichtlijnen en weinig verkeer. Dit lint vormt een goede verbinding op de regionale fietsroutes richting Noordwijkerhout. — Lisse / noordelijk bollengebied' WHERE slug = 'via-nova-1';
UPDATE locations SET full_description = 'De Via Nova in Lisse-Noord loopt door een aaneengesloten bollenteeltzone met percelen die in het bloeiseizoen intensief kleurspektakel bieden. De naam ''Via Nova'' verwijst naar de relatief jonge ontginning of aanleg van dit traject. — Lisse / noordelijk bollengebied' WHERE slug = 'via-nova-2';
UPDATE locations SET full_description = 'De Vogelaarsdreef vormt onderdeel van de fiets- en wandelroutes door het noorden van Noordwijk, een minder bezochte maar bijzonder rustige hoek van de Bollenstreek. De omgeving biedt ongestoorde zichtlijnen over de bollenvelden. — Noordwijk / noord-bollengebied' WHERE slug = 'vogelaarsdreef-1';
UPDATE locations SET full_description = 'De Vogelaarsdreef in het noorden van Noordwijk doorsnijdt een actief bollenteeltgebied op de geestrug. De percelen langs deze dreef worden jaarlijks beplant met wissellende bolgewassen, wat een dynamisch kleurlandschap oplevert. — Noordwijk / noord-bollengebied' WHERE slug = 'vogelaarsdreef-2';
UPDATE locations SET full_description = 'Aan het beginpunt van het Westeinde sluit het lint aan op de grotere verbindingswegen die het westelijke bollengebied van Noordwijk ontsluiten. Dit netwerk van linten is de ruggengraat van de dagelijkse logistiek voor tientallen bollenkwekerijen. — Noordwijk / bollengebied west' WHERE slug = 'westeinde-1';
UPDATE locations SET full_description = 'De percelen langs het Westeinde zijn onderdeel van de kustregio van de Bollenstreek, waar de grond door zeewind en duinzand een lichtere textuur heeft dan in de poldergebieden verder inland. Dit maakt de grond bijzonder geschikt voor bollenteelt. — Noordwijk / Westeinde-lint' WHERE slug = 'westeinde-2';
UPDATE locations SET full_description = 'Langs het Westeinde zijn in april bloeiende tulpen- en hyacintenvelden te zien die de weg aan beide zijden omlijsten. De geur van hyacinten hangt in het bloeiseizoen vaak ver over het land in dit open kustgebied. — Noordwijk / Westeinde-lint' WHERE slug = 'westeinde-3';
UPDATE locations SET full_description = 'Het noordelijke deel van het Westeinde ligt vlak bij het duingebied van de Langevelderduinen en vormt een mooie etappe op de fietsroute langs de bollenvelden van Noordwijk. De combinatie van zee-lucht en bloemenkleur maakt dit een bijzondere belevenis. — Noordwijk / Westeinde-lint noord' WHERE slug = 'westeinde-4';
UPDATE locations SET full_description = 'Langs het Westeinde liggen bollenvelden die in het voorjaar felle kleuren vertonen tegen de groene achtergrond van de nabijgelegen duinen. Het lint biedt een schilderachtig beeld van de Bollenstreek op haar meest westers. — Noordwijk / Westeinde-lint' WHERE slug = 'westeinde-5';
UPDATE locations SET full_description = 'Het Westeinde in Noordwijk vormt de westelijke grens van het bollengebied richting de duinen. Percelen langs dit lint worden beplant met bolgewassen die goed gedijen op de lichter grond nabij de duinrand. — Noordwijk / Westeinde-lint' WHERE slug = 'westeinde-6';
UPDATE locations SET full_description = 'Aan de Westelijke Randweg in Lisse is de overgang zichtbaar tussen het bebouwde dorpsgebied en de open bollenpercelen. Dit type randen zijn kenmerkend voor de Bollenstreek, waar dorp en teeltgebied direct op elkaar grenzen. — Lisse / westrand' WHERE slug = 'westelijke-randweg-1';
UPDATE locations SET full_description = 'De Westelijke Randweg vormt een ontsluitingsas aan de rand van de Lisser bebouwing en verbindt de omliggende bollenteeltgebieden met de doorgaande infrastructuur. Deze randwegen zijn essentieel voor het dagelijkse logistieke verkeer van bollenkwekers. — Lisse / westrand' WHERE slug = 'westelijke-randweg-2';
UPDATE locations SET full_description = 'De naam Wilgendam verwijst naar een historische dam met wilgenbeplanting in dit waterrijke deel van het bollengebied. Dammetjes en slootjes waren essentieel in het waterbeheer dat de bollenteelt mogelijk maakte. — Noordwijk / waterzone bollengebied' WHERE slug = 'wilgendam-1';
UPDATE locations SET full_description = 'Langs de Wilgendam in Noordwijk wisselen bollenpercelen af met slootkanten bezet met riet en wilgen. Dit mozaïeklandschap is karakteristiek voor de overgang van geestgrond naar lager gelegen waterrijke zones. — Noordwijk / waterzone bollengebied' WHERE slug = 'wilgendam-2';
UPDATE locations SET full_description = 'De Wilhelminalaan in Lisse is vernoemd naar koningin Wilhelmina, die in de vroege twintigste eeuw symbool stond voor de Nederlandse identiteit. In de Bollenstreek droegen veel straatnamen de naam van de oranjes, mede dankzij de sterke band tussen de bollensector en het koningshuis. — Lisse / noordelijk dorpslint' WHERE slug = 'wilheminalaan-1';
UPDATE locations SET full_description = 'Aan het zuidelijke begin van de Zilkerbinnenweg start een rustige fietsroute richting De Zilk, een van de kleinste en meest authentieke bollendorpen in de regio. De omgeving is in het bloeiseizoen een stille, kleurrijke tegenhanger van de drukkere toeristische routes. — Lisse / zuidelijke bollenrand' WHERE slug = 'zilkerbinnenweg-1';
UPDATE locations SET full_description = 'De Zilkerbinnenweg is een van de oudste ontsluitingswegen in dit deel van de Bollenstreek en maakte deel uit van het agrarische wegennet dat al voor de intensivering van de bollenteelt bestond. De weg verbindt twee dorpsgemeenschappen die decennialang nauw samenwerkten in de bollenhandel. — Lisse–De Zilk / historisch lint' WHERE slug = 'zilkerbinnenweg-2';
UPDATE locations SET full_description = 'In april kleuren de bollenvelden langs de Zilkerbinnenweg prachtig, met rijen hyacinten en tulpen die de horizon bepalen. De geur van hyacinten hangt op windstille ochtenden zwaar boven het land. — Lisse–De Zilk / bollenzone' WHERE slug = 'zilkerbinnenweg-3';
UPDATE locations SET full_description = 'Langs de Zilkerbinnenweg liggen bollenpercelen ingeklemd tussen duinrand en polderzone, met hier en daar een bollenschuur of sorteerhal in het landschap. Dit is het stille werklandschap achter het toeristische beeld van de Bollenstreek. — Lisse–De Zilk / bollenzone' WHERE slug = 'zilkerbinnenweg-4';
UPDATE locations SET full_description = 'De Zilkerbinnenweg is een van de kenmerkende linten in het bollengebied tussen Lisse en De Zilk, een zone met intensieve bollenteelt op lichte zandgrond. De weg verbindt twee klassieke bollendorpen met een doorgaand teeltlandschap. — Lisse–De Zilk / bollenzone' WHERE slug = 'zilkerbinnenweg-5';
UPDATE locations SET full_description = 'De oevers van de Zuider Leidsevaart zijn in het bloeiseizoen een geliefd wandel- en fietsgebied. Wie het jaagpad volgt, heeft regelmatig vrij zicht over kleurrijke bollenvelden aan weerszijden van het water. — Lisse / Leidsevaart-lint' WHERE slug = 'zuider-leidsevaart-1';
UPDATE locations SET full_description = 'De Leidsevaart werd in de zeventiende eeuw gegraven als verbinding tussen Leiden en Haarlem en doorkruist de Bollenstreek als een historische slagader. Langs dit kanaal werden ook bloembollen en andere agrarische producten vervoerd. — Lisse / Leidsevaart-lint' WHERE slug = 'zuider-leidsevaart-2';
UPDATE locations SET full_description = 'Langs de Zuider Leidsevaart wisselen bollenvelden, waterloopoevers en rietland elkaar af, wat een gevarieerd landschapsbeeld oplevert. De vaart vormt een ecologische verbinding in het verder strak ingedeelde bollengebied. — Lisse / Leidsevaart-zone' WHERE slug = 'zuider-leidsevaart-3';
UPDATE locations SET full_description = 'De Zuider Leidsevaart is een historisch waterkanaal dat een belangrijke rol speelde in de afvoer en het transport van bollenprodukten in de Bollenstreek. Vaarten als deze verbonden de teeltgebieden met opslagplaatsen en exportpunten. — Lisse / Leidsevaart-zone' WHERE slug = 'zuider-leidsevaart-4';
UPDATE locations SET full_description = 'Langs de Zwartelaan grenst bollengrond aan de overgang naar de duinrand, een zone die typisch is voor de teelt van narcissen en vroege tulpenrassen. De lichtere grond hier warmt snel op in het vroege voorjaar. — Lisse / binnenduinrand' WHERE slug = 'zwartelaan-1';
UPDATE locations SET full_description = 'De Zwartelaan loopt door een overgangsgebied met bollenpercelen en restanten van het oorspronkelijke duinlandschap. De naam verwijst mogelijk naar donkere vegetatie of vochtige grond langs dit historische pad. — Lisse / binnenduinrand' WHERE slug = 'zwartelaan-2';
UPDATE locations SET full_description = 'De Zwarteweg in Noordwijk verwijst mogelijk naar de donkere, vochtige ondergrond die op deze locatie voorkomt langs de duinrand. Dit type namen zijn typisch voor de Hollandse naamgevingstraditie, gebaseerd op zichtbare kenmerken van het landschap. — Noordwijk / duinrand' WHERE slug = 'zwarteweg';
